            "sendersChargesOne": "USD0",
            "sendersChargesTwo": "USD0",
            "sendersChargesThree": "USD0",
            "sendersChargesFour": "USD0"
        },
        "instructedAmount": {
            "currencyCode": "USD",
            "amount": "000000000250"
        },
        "exchangeRate": {
